mapper.select:
/* 사용자 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				a.user_idx, a.user_id, a.auth_type, a.auth_type_name, b.comp_name, c.site_grp_name, a.note, a.reg_date
			from (
				select 
					user_idx, user_id, user_pw, user_type, main_user_idx, main_user_yn, auth_type, 
					case auth_type when 1 then '포털관리자'
					when 2 then '고객사관리자'
					when 3 then '그룹관리자'
					when 4 then '사이트관리자'
					when 5 then '사이트이용자'
					else '' end as auth_type_name,
					lang_type, 
					case lang_type when 1 then '한국어'
					when 2 then '영어'
					when 3 then '일본어'
					else '' end as lang_type_name,
					comp_idx, co_name, co_tel, co_email, psn_name, psn_dept, psn_tel, psn_mobile, psn_email, note, site_grp_idx, site_id,
					del_yn, reg_uid, reg_date, mod_uid, mod_date 
				from tb_user
				where del_yn = 'N'
			) a left outer join tb_company b
			on a.comp_idx = b.comp_idx
			left outer join tb_site_group c
			on a.site_grp_idx = c.site_grp_idx
			where 1=1

			and b.comp_idx = #{compIdx }


			and c.site_grp_idx = #{siteGrpIdx }


			and a.site_id = #{siteId }


			and a.user_idx = #{userIdx }

	) page_tb
	,  ( select @rownum := 0 ) r
	order by reg_date desc
) f_tb
limit #{startNum }, #{pageRowCnt }

select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				a.user_idx, a.user_id, a.auth_type_name, b.comp_name, c.site_grp_name, a.note, a.reg_date
			from (
				select 
					user_idx, user_id, user_pw, user_type, main_user_idx, main_user_yn, auth_type, 
					case auth_type when 1 then '포털관리자'
					when 2 then '고객사관리자'
					when 3 then '그룹관리자'
					when 4 then '사이트관리자'
					when 5 then '사이트이용자'
					else '' end as auth_type_name,
					lang_type, 
					case lang_type when 1 then '한국어'
					when 2 then '영어'
					when 3 then '일본어'
					else '' end as lang_type_name,
					comp_idx, co_name, co_tel, co_email, psn_name, psn_dept, psn_tel, psn_mobile, psn_email, note, site_grp_idx, site_id,
					del_yn, reg_uid, reg_date, mod_uid, mod_date 
				from tb_user
				where del_yn = 'N'
			) a left outer join tb_company b
			on a.comp_idx = b.comp_idx
			left outer join tb_site_group c
			on a.site_grp_idx = c.site_grp_idx
			where 1=1

			and b.comp_idx = #{compIdx }


			and c.site_grp_idx = #{siteGrpIdx }


			and a.site_id = #{siteId }


			and a.user_idx = #{userIdx }

	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

