/* 사용자 삭제 */
delete from tb_user
where user_idx = #{userIdx }

/* 사용자 권한 수정 */ update tb_user set
comp_idx = #{compIdx }, /* 회사식별자 */ site_grp_idx = #{siteGrpIdx }, /* 사이트그룹식별자 */ site_id = #{siteId }, /* 사이트ID */
site_grp_idx = #{siteGrpIdx }, /* 사이트그룹식별자 */ site_id = #{siteId }, /* 사이트ID */
site_id = #{siteId }, /* 사이트ID */
mod_uid = #{modUid }, mod_date = now() where user_idx = #{userIdx }

